CODE_EXAMPLE:
// Before
class JobItem {
  int getTotalPrice() { ... }
  String getUnitPrice() { ... }
  String getEmployee() { ... } // only for some items
}

// After
class JobItem {
  int getTotalPrice() { ... }
  String getUnitPrice() { ... }
}

class LaborItem extends JobItem {
  String getEmployee() { ... }
}

UNIT_TEST_EXAMPLE:
@Test
public void testExtractSubclass() {
  JobItem item = new JobItem();
  assertTrue(item instanceof JobItem);

  LaborItem laborItem = new LaborItem();
  assertEquals("John", laborItem.getEmployee());
}
